var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"크윽! 끝이 없잖아…!!","JPN":"くっ！　切りがない……！！","ENG":"Kgh! They just keep coming...!","TWN":"咳呃！沒完沒了……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"무슨 거울이랑 가위바위보 하는 것도 아니고, 이러다가 이쪽이 먼저 나가떨어지겠어!","JPN":"鏡とジャンケンしてるみたいで、これじゃこっちが先にぐたぐたになるよ！","ENG":"Feels like playing rock-paper-scissors against a mirror. We'll be the ones dropping first at this rate!","TWN":"這可不是和鏡子玩剪刀石頭布，這樣下去我這邊會先撐不住的！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침착해라. 결국 무구의 힘에 깃댄 일시적인 침식 현상에 불과해.","JPN":"落ち着け。結局は武具の力に頼った一時的な侵食現象だ。","ENG":"Stay calm. This is just a temporary Counterside Effect caused by the Armament's power.","TWN":"冷靜點。這不過是暫時的侵蝕現象，最終會消散在武具的力量中。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그림자 전당과 달리 전투가 길어지더라도 현상이 악화되지는 않을 거야.","JPN":"影の殿堂とは違い、戦闘が長くなっても現象が悪化することはないだろう。","ENG":"Unlike the Shadow Palaces, the effect won't worsen even if the fight drags on.","TWN":"與暗影殿堂不同，即使戰鬥拖延，現象也不會惡化。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무구를 갖춘 도플갱어 침식체들은 내가 막겠다!","JPN":"武具を持っている侵食体は私が止める！","ENG":"I'll take care of the Doppelganger-types with weapons!","TWN":"我會阻止那些裝備武具的化身侵蝕體！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"상대적으로 약한 침식체들을 우선 공격하여, 수의 우위로 놈들을 밀어붙이도록!","JPN":"比較的弱い侵食体を優先的に攻撃し、数的優位でやつらを追い込むのだ！","ENG":"Everyone else, focus on the weaker ones! Push through with numbers!","TWN":"優先攻擊相對較弱的侵蝕體，以數量優勢壓制他們！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"적의 수가 줄어들고는 있으나, 다들 연전으로 지친 탓에 그 속도가 더디다.","JPN":"敵の数は減っているが、みんな連戦で疲れているため、その速度が徐々に低下している。","ENG":"The enemy's thinning out, but everyone's exhausted from constant combat. Progress is too slow.","TWN":"敵人的數量雖然在減少，但由於大家連續作戰疲憊不堪，速度變得緩慢。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"시간을 소모한다면 길을 뚫을 수 있겠지만, 이런 소모전을 계속해서는…….","JPN":"時間をかければ道を開けることはできるはずだが、こんな消耗戦を続けては……","ENG":"We might break through if we hold out, but we can't keep up this attrition...","TWN":"如果耗費時間的話，雖然可以開闢道路，但這樣持續消耗戰的話……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"역시, 그 방법밖에 없나.","JPN":"やはり、あの方法しかないか。","ENG":"Looks like we don't have a choice.","TWN":"果然，只有那個辦法了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KNIGHT_NPC_NULL_C","text":{"KOREA":"6시 방향! 침식체 무리가 돌격합니다!!","JPN":"6時の方角！　侵食体の群れが突撃してきます！","ENG":"Six o'clock! A horde of C.O.s charging in!","TWN":"6點鐘方向！侵蝕體群正在衝鋒！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"KNIGHT_NPC_NULL_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"진형을 갖추고 피해에 대비해! 내가 앞서 놈들을 흩트리겠다!","JPN":"陣形を整え、攻撃に備えろ！　私が先鋒でやつらを蹴散らす！","ENG":"Form ranks and brace for impact! I'll go ahead and break their line!","TWN":"準備陣型，做好防禦！我會先去擾亂它們！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오케이! 맡겨만 둬-!!","JPN":"オッケー！　任せてー！！","ENG":"Got it! Leave it to me!","TWN":"好的！交給我吧-！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"부, 부단장? 갑자기 끼어들다니. 이게 무슨 짓인가?","JPN":"ふ、副団長？　いきなり割り込んでくるなんて。何をしている！","ENG":"D-Deputy? Why did you jump in?! What are you doing?","TWN":"副、副團長？突然插進來。這是幹什麼？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"분하지만 지친 저희로서는 당신의 싸움에 도움이 될 수 없습니다.","JPN":"悔しいですが、疲れている私たちではあなたの力になれません。","ENG":"As much as I hate to admit it, we're too worn out to be of any use to your fight.","TWN":"雖然不甘心，但我們已經疲憊不堪，無法在戰鬥中幫助你。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그러니 단장님은 오롯이 그 남자와의 싸움에 전념하시죠.","JPN":"ですので、団長はあの男との戦いに専念してください。","ENG":"So please, focus everything you have on defeating him.","TWN":"所以團長你就專心與那個男人戰鬥吧。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그것이 저희가 승리할 수 있는 유일한 방법입니다.","JPN":"それが私たちが勝利できる唯一の方法です。","ENG":"That's the only way we can win.","TWN":"那是我們唯一能贏的方法。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무슨 소리를 하는 건가, 부단장!","JPN":"何を言っている、副団長！","ENG":"What are you saying, Deputy?!","TWN":"你在說什麼，副團長！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"도움이 안 된다니. 난 그런 생각은…!!","JPN":"力になれないなんて。私はそんなこと……！！","ENG":"You're not useless. I never thought that for a second...!","TWN":"說我沒幫上忙。我可不這麼想……！！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"착각이 심하시군요, 단장님은!","JPN":"とんでもない勘違いです、団長！","ENG":"You're being delusional, Captain!","TWN":"你真是誤會了，團長！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"유구한 역사를 자랑해온 기사단이 단장님 한 분 없다고 무너질 것 같습니까?","JPN":"長い歴史を誇る騎士団が、団長がいないからって崩れると思っているのですか？","ENG":"Do you really think the Order, with its proud legacy, would fall without you?!","TWN":"擁有悠久歷史的騎士團會因為沒有團長而崩潰嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"단장님이 저희를 지키실 필요는 없습니다!","JPN":"団長が私たちを守る必要はありません！","ENG":"You don't need to protect us!","TWN":"團長你不需要保護我們！"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};